function smartJSONParse(jsonString) {
    let input = jsonString.trim();

    // 1. Markdown/Code-block stripping
    input = input.replace(/^```json\s*/, '').replace(/```$/, '').trim();

    const attemptParse = (str) => {
        try { return JSON.parse(str); } catch(e) { return null; }
    };

    // Try native first
    let result = attemptParse(input);
    if (result) return result;

    console.warn("Malformed JSON detected. Initiating Structural Healing...");

    // 2. Structural Reconstruction
    let fixed = input;

    // Fix missing leading/trailing brackets
    if (fixed.startsWith('{') && fixed.endsWith('}')) fixed = '[' + fixed + ']';
    else if (fixed.startsWith('{') && !fixed.startsWith('[')) fixed = '[' + fixed;
    else if (fixed.endsWith('}') && !fixed.endsWith(']')) fixed = fixed + ']';
    else if (fixed.startsWith('"action"')) fixed = '[{' + fixed + '}]';

    // 3. Delimiter & Syntax Healing
    fixed = fixed
        .replace(/}\s*{/g, '},{')             // Fix missing commas between objects
        .replace(/,\s*]/g, ']')                // Fix trailing commas
        .replace(/\\(?!["\\/bfnrtu])/g, "\\\\") // Double-escape illegal backslashes
        .replace(/(\n)/g, (match, p1, offset) => { // Handle literal newlines in strings
            const before = fixed.slice(0, offset);
            const quoteCount = (before.match(/"/g) || []).length;
            return (quoteCount % 2 === 1) ? "\\n" : "\n";
        });

    result = attemptParse(fixed);
    if (result) {
        document.getElementById('json-input').value = JSON.stringify(result, null, 2);
        saveState();
        showGlobalToast("✨ Payload Structures Healed");
        return result;
    }

    throw new Error("JSON too corrupted for auto-fix. Check brackets/commas manually.");
}

